def patch_pages():
 idx=SITE/'cognitive-lab/index.html';it=idx.read_text(encoding='utf-8')
 for slug,title,cat,mode,ins in TOOLS:
  p=SITE/'cognitive-lab'/slug/'index.html';t=p.read_text(encoding='utf-8');m=re.search(r'<script type="application/json" id="lab-definition">(.*?)</script>',t,re.S);d=json.loads(m.group(1));new={**d,'title':title,'category':cat,'summary':SUM[slug],'mode':mode,'stages':5,'trials_per_stage':6,'instructions':ins,'version':24};payload=json.dumps(new,ensure_ascii=False,separators=(',',':')).replace('</','<\\/');t=t[:m.start(1)]+payload+t[m.end(1):];t=t.replace(d.get('title',''),title).replace(d.get('summary',''),SUM[slug]);marker='<div class="question"><strong>مهم:</strong>'
  if ins not in t:t=t.replace(marker,f'<div class="question"><strong>طريقة الاستخدام:</strong> {ins}</div>{marker}',1)
  p.write_text(t,encoding='utf-8')
  pat=rf'(<a class="lab-v12__card" href="[^"]*{slug}[^"]*">.*?<h2>)(.*?)(</h2><p>)(.*?)(</p>)';it,n=re.subn(pat,lambda m:m.group(1)+title+m.group(3)+SUM[slug]+m.group(5),it,count=1,flags=re.S)
  if n!=1:raise SystemExit(f'index patch failed {slug}')
 idx.write_text(it,encoding='utf-8')

